/**
 * AiSettingsDialog — configure AI (Ollama) connection and model.
 * Mirrors a settings panel for the AI assistant integration.
 */

import React, { useState, useCallback } from 'react';
import {
  Dialog, DialogTitle, DialogContent, DialogActions, Button,
  TextField, Box, Typography, FormControl, InputLabel, Select, MenuItem,
  Slider, Divider, Alert,
} from '@mui/material';
import { useUIStore } from '../../stores';
import { useAiStore } from '../../stores/useAiStore.js';

const AiSettingsDialog: React.FC = () => {
  const openDialog = useUIStore((s) => s.openDialog);
  const closeDialog = useUIStore((s) => s.closeDialog);
  const open = openDialog === 'aiSettings';

  const aiConfig = useAiStore((s) => s.config);
  const setAiConfig = useAiStore((s) => s.setConfig);

  const [baseUrl, setBaseUrl] = useState(aiConfig?.baseUrl ?? 'http://localhost:11434');
  const [model, setModel] = useState(aiConfig?.model ?? 'llama3.1:8b');
  const [temperature, setTemperature] = useState(aiConfig?.temperature ?? 0.7);
  const [maxTokens, setMaxTokens] = useState(aiConfig?.maxTokens ?? 2048);
  const [systemPrompt, setSystemPrompt] = useState(
    aiConfig?.systemPrompt ??
    'You are a project management assistant. Help users plan, schedule, and manage their projects effectively.'
  );
  const [testStatus, setTestStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');

  const handleTestConnection = useCallback(async () => {
    setTestStatus('testing');
    try {
      const res = await fetch(`${baseUrl}/api/tags`);
      if (res.ok) {
        setTestStatus('success');
      } else {
        setTestStatus('error');
      }
    } catch {
      setTestStatus('error');
    }
  }, [baseUrl]);

  const handleSave = useCallback(() => {
    setAiConfig({ baseUrl, model, temperature, maxTokens, systemPrompt });
    closeDialog();
  }, [baseUrl, model, temperature, maxTokens, systemPrompt, setAiConfig, closeDialog]);

  if (!open) return null;

  return (
    <Dialog open={open} onClose={closeDialog} maxWidth="sm" fullWidth>
      <DialogTitle>AI Settings</DialogTitle>
      <DialogContent>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, mt: 1 }}>
          <Typography variant="subtitle2">Connection</Typography>

          <TextField
            size="small"
            label="Ollama Base URL"
            value={baseUrl}
            onChange={(e) => setBaseUrl(e.target.value)}
            fullWidth
            helperText="Default: http://localhost:11434"
          />

          <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
            <Button size="small" variant="outlined" onClick={handleTestConnection}
              disabled={testStatus === 'testing'}
            >
              {testStatus === 'testing' ? 'Testing...' : 'Test Connection'}
            </Button>
            {testStatus === 'success' && <Alert severity="success" sx={{ py: 0, flex: 1 }}>Connected</Alert>}
            {testStatus === 'error' && <Alert severity="error" sx={{ py: 0, flex: 1 }}>Failed to connect</Alert>}
          </Box>

          <Divider />
          <Typography variant="subtitle2">Model</Typography>

          <FormControl size="small" fullWidth>
            <InputLabel>Model</InputLabel>
            <Select value={model} label="Model" onChange={(e) => setModel(e.target.value)}>
              <MenuItem value="llama3.1:8b">Llama 3.1 8B</MenuItem>
              <MenuItem value="llama3.1:70b">Llama 3.1 70B</MenuItem>
              <MenuItem value="codellama:7b">Code Llama 7B</MenuItem>
              <MenuItem value="codellama:34b">Code Llama 34B</MenuItem>
              <MenuItem value="mistral:7b">Mistral 7B</MenuItem>
              <MenuItem value="mixtral:8x7b">Mixtral 8x7B</MenuItem>
              <MenuItem value="phi3:mini">Phi-3 Mini</MenuItem>
            </Select>
          </FormControl>

          <Divider />
          <Typography variant="subtitle2">Parameters</Typography>

          <Box>
            <Typography variant="body2" gutterBottom>Temperature: {temperature.toFixed(1)}</Typography>
            <Slider
              value={temperature}
              onChange={(_, v) => setTemperature(v as number)}
              min={0} max={2} step={0.1}
              marks={[
                { value: 0, label: '0' },
                { value: 0.7, label: '0.7' },
                { value: 2, label: '2' },
              ]}
              size="small"
            />
          </Box>

          <TextField
            size="small"
            label="Max Tokens"
            type="number"
            value={maxTokens}
            onChange={(e) => setMaxTokens(Number(e.target.value))}
            fullWidth
          />

          <Divider />
          <Typography variant="subtitle2">System Prompt</Typography>

          <TextField
            multiline
            minRows={3}
            maxRows={6}
            fullWidth
            size="small"
            value={systemPrompt}
            onChange={(e) => setSystemPrompt(e.target.value)}
            helperText="This prompt is sent with every AI request to set the assistant's behavior."
          />
        </Box>
      </DialogContent>
      <DialogActions>
        <Button onClick={closeDialog}>Cancel</Button>
        <Button variant="contained" onClick={handleSave}>Save</Button>
      </DialogActions>
    </Dialog>
  );
};

export default AiSettingsDialog;
